type DotStyle = {
  top: number;
  left: number;
  width: number;
  height: number;
};

export function buildConnectionDotStyle(
  dotTop: number,
  leftPx: number,
): DotStyle {
  const dotSize = 4;
  return {
    top: dotTop,
    left: leftPx,
    width: dotSize,
    height: dotSize,
  };
}

